import { useEffect, useState } from "react";
import api from "../api";

export default function Users() {
    const [rows, setRows] = useState([]);
    const [loading, setLoading] = useState(true);
    useEffect(()=>{
        (async ()=>{
            setLoading(true);
            try {
                const { data } = await api.get("/api/users");
                setRows(data||[]);
            } finally { setLoading(false); }
        })();
    },[]);
    return (
        <div className="space-y-4">
            <h2 className="text-lg font-semibold">Người dùng & Phân quyền</h2>
            <div className="bg-white rounded-2xl border border-indigo-100 shadow overflow-hidden">
                <div className="overflow-auto">
                    <table className="min-w-full">
                        <thead className="bg-indigo-50">
                        <tr className="text-left text-slate-600">
                            <th className="px-4 py-3">Tên</th>
                            <th className="px-4 py-3">Email</th>
                            <th className="px-4 py-3">Vai trò</th>
                        </tr>
                        </thead>
                        <tbody className="divide-y">
                        {!loading && rows.map(u=>(
                            <tr key={u.id} className="hover:bg-indigo-50/40">
                                <td className="px-4 py-3 font-medium">{u.username||u.name}</td>
                                <td className="px-4 py-3">{u.email||"-"}</td>
                                <td className="px-4 py-3">{Array.isArray(u.roles)?u.roles.join(", "):u.roles||"-"}</td>
                            </tr>
                        ))}
                        {loading && <tr><td className="px-4 py-3" colSpan={3}>Đang tải...</td></tr>}
                        {!loading && rows.length===0 && <tr><td className="px-4 py-3" colSpan={3}>Không có dữ liệu</td></tr>}
                        </tbody>
                    </table>
                </div>
            </div>
        </div>
    );
}
